  ('dietitian-moex-02488', 'dietitian', 'dietitian-moex-105-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '某團膳公司採用「一物一票方式」進行庫房管理。某甲將乾香菇庫存量依南北貨項目填入丙票內，交給 某乙做核對庫存量之依據，則下列敘述何者錯誤？', '["此種庫房管理為「貨物標籤方法」", "某甲為盤點人員", "某乙為採購人員", "丙票為貨物標籤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:59+00:00", "source_pdf_sha1": "daeaf2290b6f", "answer_pdf_sha1": "49b5ca78f6a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
