  ('dietitian-moex-02491', 'dietitian', 'dietitian-moex-105-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '正確的驗收流程為何？①移至庫房或廚房  ②接受進貨或退貨  ③查對送貨單或發票  ④依訂單進行驗 收  ⑤完成驗收紀錄', '["", "", "", "⑤"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:59+00:00", "source_pdf_sha1": "daeaf2290b6f", "answer_pdf_sha1": "49b5ca78f6a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-02492', 'dietitian', 'dietitian-moex-105-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '關於白米驗收的敘述，下列何者正確？', '["取出白米附著之粉末加少許水後，置於兩塊玻璃間磨擦，玻璃上沒有滑痕者，為參雜白粉", "蓬萊米，米粒長形；在來米，米粒圓形", "二期米與一期米比較，米粒較大", "夾雜物是取檢定雜物內之石頭"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:59+00:00", "source_pdf_sha1": "daeaf2290b6f", "answer_pdf_sha1": "49b5ca78f6a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
